chrome.tabs.query({}, function(tabs) {
  var currentTabId = chrome.tabs.getCurrent ? null : null;
  chrome.tabs.getCurrent(function(current) {
    var currentId = current.id;
    var toClose = tabs.filter(function(t) { return t.id !== currentId; });
    var ids = toClose.map(function(t) { return t.id; });
    chrome.tabs.remove(ids, function() {
      console.log('Closed tabs:', ids.length, 'remaining tab id:', currentId);
    });
  });
});
